import React, { useState } from "react";
import * as api from "../utils/api";
import "./AppointmentForm.css";

const initialForm = {
  patientId: "",
  doctorId: "",
  appointmentDate: "",
  appointmentTime: "",
  reason: "",
};

export default function AppointmentForm() {
  const [form, setForm] = useState(initialForm);
  const [errors, setErrors] = useState({});
  const [successMessage, setSuccessMessage] = useState("");
  const [serverError, setServerError] = useState("");

  const handleChange = (field) => (e) => {
    setForm({ ...form, [field]: e.target.value });
    setErrors((prev) => ({ ...prev, [field]: "" }));
    setSuccessMessage("");
    setServerError("");
  };

  const validate = () => {
    const e = {};
    if (!form.patientId) e.patientId = "Patient is required";
    if (!form.doctorId) e.doctorId = "Doctor is required";
    if (!form.appointmentDate)
      e.appointmentDate = "Appointment date is required";
    if (!form.appointmentTime)
      e.appointmentTime = "Appointment time is required";
    if (!form.reason) e.reason = "Reason is required";

    setErrors(e);
    return Object.keys(e).length === 0;
  };

  const handleSubmit = () => {
    setSuccessMessage("");
    setServerError("");

    if (!validate()) {
      return;
    }

    // The tests spy on api.createAppointment and control whether it resolves or rejects
    api
      .createAppointment({
        patientId: form.patientId,
        doctorId: form.doctorId,
        appointmentDate: form.appointmentDate,
        appointmentTime: form.appointmentTime,
        reason: form.reason,
      })
      .then(() => {
        // success path
        setForm(initialForm);
        setErrors({});
        setSuccessMessage("Appointment successfully booked");
      })
      .catch(() => {
        // error path for the test that mocks rejection
        setServerError("Server error");
      });
  };

  return (
    <div className="appointment-card">
      <h2 className="appointment-title">Book Appointment</h2>
      <form className="appointment-form">
        {/* Patient */}
        <div className="form-group">
          <label className="field-label">Patient</label>
          <select
            data-testid="patient-select"
            className="field-input"
            value={form.patientId}
            onChange={handleChange("patientId")}
          >
            <option value="">Select patient</option>
            {/* static options are fine, tests only care about changing value */}
            <option value="1">Alice</option>
            <option value="2">Bob</option>
          </select>
          {errors.patientId && (
            <div className="field-error">{errors.patientId}</div>
          )}
        </div>

        {/* Doctor */}
        <div className="form-group">
          <label className="field-label">Doctor</label>
          <select
            data-testid="doctor-select"
            className="field-input"
            value={form.doctorId}
            onChange={handleChange("doctorId")}
          >
            <option value="">Select doctor</option>
            <option value="1">Dr. Smith (Cardiology)</option>
            <option value="2">Dr. Jane (Neurology)</option>
          </select>
          {errors.doctorId && (
            <div className="field-error">{errors.doctorId}</div>
          )}
        </div>

        {/* Date */}
        <div className="form-group">
          <label className="field-label">Appointment date</label>
          <input
            type="date"
            data-testid="date-input"
            className="field-input"
            value={form.appointmentDate}
            onChange={handleChange("appointmentDate")}
          />
          {errors.appointmentDate && (
            <div className="field-error">{errors.appointmentDate}</div>
          )}
        </div>

        {/* Time */}
        <div className="form-group">
          <label className="field-label">Appointment time</label>
          <input
            type="time"
            data-testid="time-input"
            className="field-input"
            value={form.appointmentTime}
            onChange={handleChange("appointmentTime")}
          />
          {errors.appointmentTime && (
            <div className="field-error">{errors.appointmentTime}</div>
          )}
        </div>

        {/* Reason */}
        <div className="form-group">
          <label className="field-label">Reason for appointment</label>
          <textarea
            data-testid="reason-input"
            className="field-input textarea-field"
            value={form.reason}
            onChange={handleChange("reason")}
          />
          {errors.reason && (
            <div className="field-error">{errors.reason}</div>
          )}
        </div>

        {/* Messages */}
        {serverError && (
          <div className="field-error">{serverError}</div>
        )}
        {successMessage && (
          <div className="field-success">{successMessage}</div>
        )}

        {/* Must ALWAYS be enabled according to tests */}
        <button
          type="button"
          className="primary-btn"
          onClick={handleSubmit}
        >
          Book Appointment
        </button>
      </form>
    </div>
  );
}
